	(1400,1400,1,'Ing. Jana Becherová','ing-jana-becherova','referencie/ing-jana-becherova','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Viac odkladacieho priestoru na izbách.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Pekné prostredie v chate i v okolí.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 12:53:53','2026-02-18 13:10:52','2f3647c7-aced-4214-911d-37b3a3e8aba2'),
	(1401,1401,1,'Ing. Jana Becherová','ing-jana-becherova','referencie/ing-jana-becherova','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Viac odkladacieho priestoru na izbách.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": false, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Pekné prostredie v chate i v okolí.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 12:54:21','2026-02-18 12:54:21','178d6485-45ab-4c76-b535-5b1086705afa'),
	(1402,1402,1,'V. Kondé a rodina','v-konde-a-rodina','referencie/v-konde-a-rodina','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Jediné čo nám trošku prekážalo bolo kovové kľučky v jednom apartmáne aj na toalete, dosť to bolo hlučné, keď sa ráno alebo večer otvárali dvere, aj sa s tým ťažšie pracovalo. Iné výhrady nemáme.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna chata, čisté izby vybavené aj uterákmi, väčšina izieb mala vlastnú kúpeľňu s toaletou. Tým, že sme boli veľká skupina a aj deti, tak sme sa super pomestili a pre detičky bol k dispozícii aj detský kútik, čo bolo veľké plus a aj spoločenská miestnosť s projektorom a stolným futbalom pre väčších. Kuchyňa skvelo vybavená od kávovaru, cez všetko zariadenie potrebné na varenie aj prípravu raňajok. Wellness (vírivka, sauna, oddychová miestnosť a vyhrievaný detský bazén) boli fantastické a dopriali sme si výborný oddych a nemuseli sme nikam chodiť, keďže je to súčasťou chaty, vždy sme mali všetko nachystané. Majiteľ chaty a personál sú veľmi ochotní a milí a v prípade akéhokoľvek problému a otázok boli k dispozícii. Chata je blízko lyžiarskeho strediska, často sme chodili aj pešo rovno od chaty na svah. Na chate boli dokonca k dispozícii aj sánky a iné pomôcky na sánkovanie, čo nás veľmi potešilo a aj sme to naplno využili. Za nás veľká spokojnosť a odporúčame všetkými desiatimi.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 12:54:26','2026-02-18 13:07:55','b46fc77a-9677-452c-a28b-5fbba89a55f1'),
