	(1424,1424,1,'Patrik Popelic','patrik-popelic','referencie/patrik-popelic','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Chýbal nám jedine kávovar, ktorý bol v danom čase nefunkčný, ale kaviareň bola blízko tak sme to využili.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Výborná lokalita, veľmi pekná chata, aj vybavenie. Majiteľ ústretový a veľmi príjemný. Povysvetľoval, čo nájdeme v okolí.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:05:29','2026-02-18 13:13:04','e657f557-69c9-4ad1-b777-b1a43b101449'),
	(1425,1425,1,'Patrik Popelic','patrik-popelic','referencie/patrik-popelic','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Chýbal nám jedine kávovar, ktorý bol v danom čase nefunkčný, ale kaviareň bola blízko tak sme to využili.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": false, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Výborná lokalita, veľmi pekná chata, aj vybavenie. Majiteľ ústretový a veľmi príjemný. Povysvetľoval, čo nájdeme v okolí.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:06:11','2026-02-18 13:06:11','3e35e6e7-f7d9-440d-b3bc-f00ceb36f2c8'),
	(1427,1427,1,'Jaroslav Jezkovsky','jaroslav-jezkovsky','referencie/jaroslav-jezkovsky','{\"7956c53d-2d12-414c-9756-a9859f905b17\": false, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna chata, full vybavenie so zmyslom pre detail, vkusné wellness a vonkajšie sedenie s výborným grilom... a bonus je ústretový, milý, vtipný a ochotný majiteľ.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:07:28','2026-02-18 13:07:28','ccc7f3db-fc8c-4dd5-ab92-3de64abec897'),
	(1429,1429,1,'V. Kondé a rodina','v-konde-a-rodina','referencie/v-konde-a-rodina','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Jediné čo nám trošku prekážalo bolo kovové kľučky v jednom apartmáne aj na toalete, dosť to bolo hlučné, keď sa ráno alebo večer otvárali dvere, aj sa s tým ťažšie pracovalo. Iné výhrady nemáme.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna chata, čisté izby vybavené aj uterákmi, väčšina izieb mala vlastnú kúpeľňu s toaletou. Tým, že sme boli veľká skupina a aj deti, tak sme sa super pomestili a pre detičky bol k dispozícii aj detský kútik, čo bolo veľké plus a aj spoločenská miestnosť s projektorom a stolným futbalom pre väčších. Kuchyňa skvelo vybavená od kávovaru, cez všetko zariadenie potrebné na varenie aj prípravu raňajok. Wellness (vírivka, sauna, oddychová miestnosť a vyhrievaný detský bazén) boli fantastické a dopriali sme si výborný oddych a nemuseli sme nikam chodiť, keďže je to súčasťou chaty, vždy sme mali všetko nachystané. Majiteľ chaty a personál sú veľmi ochotní a milí a v prípade akéhokoľvek problému a otázok boli k dispozícii. Chata je blízko lyžiarskeho strediska, často sme chodili aj pešo rovno od chaty na svah. Na chate boli dokonca k dispozícii aj sánky a iné pomôcky na sánkovanie, čo nás veľmi potešilo a aj sme to naplno využili. Za nás veľká spokojnosť a odporúčame všetkými desiatimi.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:07:55','2026-02-18 13:07:55','4c580ef4-0982-44ec-9d18-c0d55356cefa'),
	(1432,1432,1,'Eva Huttova','eva-huttova','referencie/eva-huttova','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Všetko, ubytovanie naozaj na vysokej úrovni, vybavenie, kde nám naozaj nič nechýbalo a veľmi milý pán, ktorý nás privítal a v prípade potreby rýchlo reagoval na správy.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:09:16','2026-02-18 13:09:16','15128c55-9ba3-42d0-a015-55da140f651d'),
	(1434,1434,1,'Renata N','renata-n','referencie/renata-n','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Keďže sa objekt prenajíma len jednej skupine, chýbal nám vo vnútri veľký gauč, kde by sme mohli pohodlne všetci spolu tráviť čas.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Vybavenie chaty bolo super, v cene jacuzzi, malý bazén pre deti a sauna. V podkroví veľký priestor, kde sa deti hrali. Super vybavená kuchyňa.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:09:27','2026-02-18 13:09:27','e79d50db-1ba5-4425-86f1-24f608b6d804'),
	(1436,1436,1,'Kristína Čičman','kristina-cicman','referencie/kristina-cicman','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Vynikajúce ubytovanie, neskutočná hracia miestnosť pre deti. Vybavenie chaty na vysokej úrovni. Ochotný a milý Majiteľ.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:09:35','2026-02-18 13:09:35','6d7072ee-9a28-4cf2-a8c2-9b80bdfabbdc'),
	(1437,1437,1,'Zuzana Lalíková','zuzana-lalikova','referencie/zuzana-lalikova','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Veľmi krásna chata, čistota na jednotku, užili sme si tu veľa spoločného času s rodinou, bolo nám úžasne.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:01','2026-02-18 13:10:01','630fddc2-8003-4d82-84aa-263b6c79c533'),
	(1439,1439,1,'Anna Kováčová','anna-kovacova','referencie/anna-kovacova','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Možno sieťky na okná a doriešiť odhlučnenie od cesty.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Strávili sme krásny čas na chate Horská Vílenka. Boli sme veľmi spokojní, majiteľ príjemný, ústretový, služby na úrovni, wellness vynikajúci. Určite sa v budúcnosti vrátime 😊😊\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:09','2026-02-18 13:10:09','8e5e9529-b73f-4919-8cf9-eeea649971da'),
	(1441,1441,1,'Adela','adela','referencie/adela','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna veľká chata, čistá, plne vybavená, super detský kútik, vonku detské ihrisko, bazén, vírivka…všetko top. Majiteľ milý. Boli sme veľmi spokojní.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:18','2026-02-18 13:10:18','73c83b4e-bcc8-4dbf-94dd-73483fec63ba'),
	(1443,1443,1,'Viera Ďuricová','viera-duricova','referencie/viera-duricova','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"boli sme skupina - rodiny s malými deťmi. Deti boli uveličené bazénom a my starší všetkým ostatným - vybavenie, sauna, jacuzzi, gril. Majiteľ milý a ústretový.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:26','2026-02-18 13:10:26','28f6fad7-ae72-48bd-9ca1-82e302ae654b'),
	(1445,1445,1,'Adriana','adriana','referencie/adriana','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"svetlo na senzor v chodbe pri apartmáne vľavo na poschodí, trošku rušilo v noci, keď sa nechali pootvorené dvere na izbe, inak všetko super\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"vybavenie chaty, dostatok priestoru, vybavenie kuchyne, krásne obliečky:)\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:35','2026-02-18 13:10:35','471a8a2d-c6bb-4d97-b23a-aa1430356f76'),
	(1447,1447,1,'Eva','eva','referencie/eva','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Rozmanitost celého objektu, vybavení relax zóny, vybavení kuchyně, čisto všude a příjemný přátelský přístup majitele.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:10:44','2026-02-18 13:10:44','6ae8364e-05b5-4351-a5e5-c2ae8ef5ac80'),
