	(1451,1451,1,'Anna Hudečeková','anna-hudecekova','referencie/anna-hudecekova','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Bolo nám u Vás veľmi dobre. Krásne izby a celý interiér, detský kútik a veľa maličkostí, ktoré nám spríjemnili pobyt. V kuchyni sme našli všetko, čo sme potrebovali.\\nPotešil nás špičkový wellness a detské ihrisko. Ceníme si denne pripravené ohniská a úvodné informácie o aktivitách v okolí.\", \"938ef046-0393-4c77-92ef-0a6254593f2d\": \"hudecekova@gmail.com\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:11:09','2026-02-18 13:11:09','a6ca449d-4d08-47d3-8258-a11694b05164'),
	(1453,1453,1,'Jaroslav Chmurovič','jaroslav-chmurovic','referencie/jaroslav-chmurovic','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Kvalitnejší kávovar a doplniť chladničku s mrazničkou, inak bez pripomienok.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Čistota, priestor pre deti - detské ihrisko, wellness, nádherné izby a zmysel pre detail v zariadení izieb a spoločenskej miestnosti, super vybavená spoločná kuchyňa - všetko tip top.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:11:20','2026-02-18 13:11:20','bbdde553-c6a1-4b3c-ab04-6dbbd9e0f55d'),
