	(1459,1459,1,'Jana Jamrišková','jana-jamriskova','referencie/jana-jamriskova','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Nič\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna veľká chata, čistá, nadštandardne vybavená, super detský kútik aj pre tých najmenších. Topkou je vírivka a sauna. Majiteľ veľmi milý a ústretový. Jednoznačne 100 % hodnotenie a odporúčanie.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:12:03','2026-02-18 13:12:03','7aaa467c-4139-4522-9343-fea4fc88f320'),
	(1461,1461,1,'Dominika Jamriskova','dominika-jamriskova','referencie/dominika-jamriskova','{\"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna chata, plne vybavená, v krásnom prostredí. Čistota, plná vybavenosť aj pre malé detičky, sauna, vírivka, množstvo atrakcií v regióne. Niet čo vytknúť. Určite by som sa vrátila :)\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:12:16','2026-02-18 13:12:16','7f8a2d4c-7e31-4c00-b640-b6131a209845'),
	(1463,1463,1,'Emília Hitková','emilia-hitkova','referencie/emilia-hitkova','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Nič\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Krásna, čistá, veľká chata, super vybavená, wellness na jednotku s hviezdičkou. Veľký dvor. Či v zime alebo v lete každý si tam nájde čo potrebuje pre svoju pohodu. Majiteľ veľmi príjemný. Vysvetlil čo a ako kde. Cítili sme sa tam veľmi dobre. Vrelo odporúčam.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:12:29','2026-02-18 13:12:29','20cdb8fb-b116-4c63-8229-b86d19eec4f1'),
