	(1506,1506,1,'Ingemar','ingemar','referencie/ingemar','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Nenašli sme\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Patrili sme medzi prvých, ktorí tu mohli byť ubytovaní. Majitelia si dali záležať na kvalite zariadenia a každých detailoch, ktoré dokonale spĺňajú očakávania aj náročného klienta. Ubytovanie je útulné a veľmi pohodlné, svoje miesto si tu nájde každá veková kategória.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"10\"}',1,'2026-02-18 13:27:37','2026-02-18 13:28:20','d6042cda-6f1d-44c1-828c-1b737db62c4e'),
