	(1508,1508,1,'Michal','michal','referencie/michal','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Keďže sme boli v termíne, keď nie je sneh ani možnosť ísť na túru, ocenili by sme viac atrakcií v okolí. Toto však ubytovateľ nemôže ovplyvniť.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"rodinaSMalymiDetmi\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Pekné, čistučké ubytovanie. Veľmi pekné zariadenie, sám by som si lepšie nezariadil :). Keby bolo už hotové wellness, bolo by to úplne tip top.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"9\"}',1,'2026-02-18 13:28:31','2026-02-18 13:29:18','a74edaa5-83ca-4f7a-a295-688ce56918a1'),
