	(1510,1510,1,'Matúš','matus','referencie/matus','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Chýbala nám trošku sauna, ktorá by ale mala byť čoskoro otvorená. Tešíme sa sem znova na pobyt, ktorý plánujeme niekedy začiatkom nového roka.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"útulné zariadenie, kde sme sa cítili príjemne, v spoločenskej miestnosti sme si kúrili v krásnej kachľovej peci a mali sme s manželkou ,,telku s plameňmi\\\"\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"9\"}',1,'2026-02-18 13:29:40','2026-02-18 13:30:30','370dd742-d71b-4be0-9839-e29251b701cc'),
