	(1513,1513,1,'Lenka','lenka','referencie/lenka','{\"1067021a-36a8-46cb-91e2-119be0058189\": \"Ešte nemali dokončené wellness, otvoriť ho chcú na zimu 2020, no bude to vyzerať super.\", \"7956c53d-2d12-414c-9756-a9859f905b17\": true, \"87e84366-72b6-47d1-b839-6bfd29f91298\": \"skupina\", \"92596713-09bf-4495-8f9a-0f51c9f1bf24\": \"Ozaj kvalitné zariadenie, výborne sa nám spalo v posteliach, lepšie ako doma, špičková spoločenská miestnosť výborne nám poslúžila keďže sme tu boli rodiny s malými aj staršími deťmi. Majitelia sa riadne vyhrali.\", \"edec709b-5781-4a88-8ce7-40703dd387d6\": \"9\"}',1,'2026-02-18 13:31:21','2026-02-18 13:31:21','450830bb-6918-4000-9d01-243ac125ba85'),
