	(1574,1574,1,NULL,'__temp_frdnsebxzcivzmpmcpxggolhgxuydxhsvjdh',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/tour/horska-vilenka?play=1&sr=-.39,.81&ss=7 frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-21 18:33:06','2026-02-21 18:33:06','a5b4ec5b-c8f7-4af8-8fe2-14c455cee65c'),
	(1575,1575,1,NULL,'__temp_zfipxcywtbnbaddpreayfbrsbedaecwkcffm',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"default\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"default\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": true}',1,'2026-02-21 18:33:06','2026-02-21 18:33:06','e5b3a8c5-6355-4985-b4db-611586ee2640'),
	(1576,1576,1,NULL,'__temp_tnxnbhvhruhjquzfbphiochdcpzpzrpxrndz',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Apartmány a izby\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1117, 1156, 1143, 1105, 1136], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Apartmány a izby\", \"value\": \"{entry:1519@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Každá izba či apartmán má svoje osobité čaro. Spálne sú priestranné, vždy pedantne upratané a do každej z nich je možné priložiť detskú postieľku. Všetky postele sú vybavené kvalitnými strunovými matracmi, páperovými vankúšmi (na požiadanie antialergické) a kvalitným textilom. <br /> </p><p>Štandardom na izbách sú osušky, uteráky, fén a na apartmánoch a v štúdiu nájdete vybavenú kuchynku s jedálenským sedením.</p>\"}',1,'2026-02-21 18:33:06','2026-02-21 18:33:06','51750584-0fab-4b9c-8bb3-c32ae93c283c'),
