	(1797,1797,1,NULL,'__temp_edllpyunecpgfgxmqbjrjblkfkmfxqgzfzlj',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Každá izba či apartmán má svoje osobité čaro. Spálne sú priestranné, vždy pedantne upratané a do každej z nich je možné priložiť detskú postieľku. Všetky postele sú vybavené kvalitnými strunovými matracmi, páperovými vankúšmi (na požiadanie antialergické) a kvalitným textilom.</p><p>Štandardom na izbách sú osušky, uteráky, fén a na apartmánoch a v štúdiu nájdete vybavenú kuchynku s jedálenským sedením.</p>\"}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','f7c44e2d-f514-43b2-b12c-66f5492a7527'),
	(1798,1798,1,NULL,'__temp_qjczwhpxxzqujwysfaizawutedmnzijjaizo',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','7ceb1d54-54da-4fce-b21e-ac0a961da835'),
	(1799,1799,1,'3D Prehliadka','3d-prehliadka',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','490e8ff8-2d72-49b0-9f25-f56e457ee85a'),
	(1800,1800,1,NULL,'__temp_rxlvbrkmqzadfrncqsyryvrqzlxfyfoqqfjw',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/tour/horska-vilenka?play=1&sr=-.12,.18&ss=43 frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','f9adf34c-486b-4172-92ad-8f65e1114790'),
	(1801,1801,1,NULL,'__temp_yemtcrmisnhmkmrkehxcruyhqqsaeafzfsmv',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','6c239b24-97b0-4a0c-b4ec-71852473a876'),
	(1802,1802,1,NULL,'__temp_pchdnustpzwvurvmxspkglyzjlfxobdmoqqs',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Rodinný apartmán\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1154, 1155, 1149, 1143, 1140], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Dve samostatné spálne, obývačka s kuchyňou, veľká kúpeľňa s vaňou. </strong></p><p>Ideálny výber pre <strong>veľkú 6-člennú rodinu, rodinu so staršími deťmi, rodinu so starými rodičmi alebo dve spriatelené rodinky</strong>. Apartmán má vlastnú vstupnú chodbu, čo umožňuje pohyb po apartmáne bez toho, aby ste rušili neskorým pochodom do kúpeľne spiace deti. Veľká „3-izbová kúpeľňa“ so sprchovým kútom a s vaňou poteší deti a rodičom dopraje priestor na záverečný relax pred spánkom. Zlatá romantická spálňa je pripravená pre páry, ktoré radi načúvajú praskotu dreva v piecke.</p>\"}',1,'2026-02-23 09:27:52','2026-02-23 09:27:52','e1d73f86-05b4-4415-9342-7c76d075ba73'),
