	(1904,1904,1,NULL,'__temp_blutnwzybeihhtzbxkvkmodrxyhfocvyrdbp',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Štúdio – izba č.6\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1117, 1118, 1119, 1121, 1120], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Manželská posteľ + rozťahovacia pohovka</strong></p><p><strong>Priestranná izba na prízemí s výhľadom do záhrady</strong>, uspôsobená spolu s kúpeľnou pre imobilných hostí. Z izby je všade blízko - do spoločenskej miestnosti, do wellness, altánku či záhrady s detským ihriskom.</p><p>Nájdeme tu <strong>plne vybavenú kuchynku</strong> - 2 platnička, drez, malá chladnička, kanvica, vybavenie pre základné stolovanie a poháre pre 4 osoby, hrnce, panvica, nože, vývrtka na víno.</p>\"}',1,'2026-02-23 09:27:56','2026-02-23 09:27:56','c98fbcc9-2091-4b62-b7ac-758e1c3bb787'),
