	(2008,2008,1,NULL,'__temp_ojdbtaovcwrhgrkszcbglqbmtafkshqbfvwt',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"560\\\" height=\\\"315\\\" src=\\\"https://www.youtube.com/embed/SJSQRloI93s?si=1wz78ld45QJ4mriN\\\" title=\\\"YouTube video player\\\" frameborder=\\\"0\\\" allow=\\\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\\\" referrerpolicy=\\\"strict-origin-when-cross-origin\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 10:24:38','2026-02-23 10:24:38','206284b6-661b-4bff-9295-6537e83172bf'),
