	(2091,2091,1,'Firemné pobyty','firemne-pobyty','ubytovanie/firemne-pobyty','{\"d401a70e-ad52-421a-9c71-f5991a71306a\": 5}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','f5790eec-512a-432f-b832-e48b97119c19'),
	(2092,2092,1,NULL,'__temp_njfczynspbaoirqywfmckvwsxuhlxyeqmxkc',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Ubytovanie je vhodné <strong>pre firmy od 12 – 20 osôb</strong>. Poloha na strednom Slovensku pod vrcholmi Nízkych Tatier napovedá, že k nám je z každého kúta Slovenska blízko. Pri príchode Vás pohostíme tradičnými chuťovkami, prevedieme Vás dokonalo pripraveným čistučkým interiérom a to všetko s profesionálnym prístup a neformálnou atmosférou. </p><p>Počkajú na Vás nenáročné vychádzky ale i väčšie expedície priamo z Horskej Vílenky. Radi pre Vás pripravíme teambuilndingové aktivity na stráňach dediny Mýto pod Ďumbierom.</p><h2>Ubytovanie</h2><ul><li>Ubytovanie v 2/3-lôžkových izbách a dvoch priestranných apartmánoch.</li><li>Spoločenská miestnosť s barom</li></ul>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','ed55c256-6e5f-4a8f-a047-6cb3c77c8c5e'),
	(2093,2093,1,NULL,'__temp_zbvqplxcfrkldclaywydsakrexoigmiwnhzv',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','e92ddf42-44a1-4b9e-b515-2b707d0833f7'),
	(2094,2094,1,'3D Prehliadka','3d-prehliadka',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"left\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','bbd7f8eb-7c96-4ae0-a569-b8ef15c082cd'),
	(2095,2095,1,NULL,'__temp_hxnwpgjfqutjqylsaqcvymxauaqardscxqkj',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/tour/horska-vilenka?play=1&sr=-.08,.47&ss=140 frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','80ae4d15-ba99-47b4-bcbd-c9753b079cbe'),
	(2096,2096,1,NULL,'__temp_pjblkgzyemylexrwnrmcmdpspbuxgxovskhf',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','83511305-9584-46d6-b9b5-66f592d1a14e'),
	(2097,2097,1,NULL,'__temp_gnvozranoyskhigdvgvmcihhvnyahbjdwreo',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Apartmány a izby\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1117, 1156, 1143, 1105, 1136], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"value\": \"{entry:1519@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Každá izba či apartmán má svoje osobité čaro. Spálne sú priestranné, vždy pedantne upratané a do každej z nich je možné priložiť detskú postieľku. Všetky postele sú vybavené kvalitnými strunovými matracmi, páperovými vankúšmi (na požiadanie antialergické) a kvalitným textilom. </p><p>Štandardom na izbách sú osušky, uteráky, fén a na apartmánoch a v štúdiu nájdete vybavenú kuchynku s jedálenským sedením.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','8903101b-dee6-4c5e-86e0-e30e97eedba2'),
	(2098,2098,1,NULL,'__temp_tiqjhtgvoscyugfolayxoputwocbeyhlltbu',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Školiaca a zasadacia miestnosť\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [542, 550, 556, 548, 549], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Multifunkčná miestnosť\", \"value\": \"{entry:1545@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Samostatný priestor pre Vaše firemné porady, školenia či workshopy. V chate tak máte priestor pre každú činnosť vášho tímu. </strong></p><p><strong>Kapacita</strong>: zasadačka 13 miest školenia 15 miest na sedenie</p><p><strong>Technické vybavenie</strong>:<br />- premietacie plátno 300\\\" ( 225 x 125 cm )<br />- kvalitný projektor<br />- flip chart<br />- písacie dosky</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','e71d6cd0-7b45-4f5e-bdd3-61575e200394'),
	(2099,2099,1,NULL,'__temp_pinukxhwazubxuwcnigbeablgvtuzluwjxkj',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Wellness v súkromí\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [435, 433, 868, 436, 872], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Wellness\", \"value\": \"{entry:1525@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vykročte v papučiach do záhrady a dovoľte si objaviť náš malý raj. Vonkajší bazén, fínska sauna s troma lavicami pre 9 osôb, ochladzovacia kaďa, solárna sprcha, odpočinková miestnosť je to, čo potrebujete k dokonalému znovuzrodeniu Na požiadanie saunu pripravíme v dohodnutý čas, a tak po príchode z výletu môže Vaše telo plynulo zrelaxovať. Prírodné bylinné esencie sú vždy k dispozícií. Pre náročnejších či zvedavých wellnesákov ponúkame <strong>saunový ceremoniál</strong>. Pravdaže nechýba záhradná kúpeľňa „Bob a Bobek“ s WC a sprchou, kde sa s radosťou určite osprchujú aj Vaše ratolesti.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','5304f4d6-54ec-416a-930e-42454cdbef76'),
	(2100,2100,1,NULL,'__temp_hpqdwhawsxcsmjzqhgcutlupewslhgwfuamo',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Altánok a záhrada\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [445, 471, 473, 470, 442], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Altánok a záhrada\", \"value\": \"{entry:1543@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Praskajúci oheň, víno s priateľmi, nekonečné debaty alebo príjemné ticho pod hviezdami. Zabavte sa pri žolíkovi či pomaly už historických dostihoch a užite si príjemné chvíle s najbližšími. Odvážnych, ale aj unavených v altánku poteší váľanda.</p><p>Dominantný VULCANO gril čaká na Vašu obľúbenú zeleninu a mäsko či pozbierané hríbiky. Gulášik pre celú rodinu pripravíte zase v nerezovej kotline.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','e05851b6-865d-4607-b388-8bb6e8a309e2'),
	(2101,2101,1,NULL,'__temp_nqhjmsutywcdwmgzaxydzqnicurozrkdyywi',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Spoločenská miestnosť\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1161, 1159, 1160, 1162, 1167], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Spoločenskú miestnosť a obývačku s detským kútikom sme navrhli tak, aby si v nej každý člen našiel svoje miesto. Kuchyňa s barom a krbom tvorí centrum diania. Barové sedenie si vychutnajú hlavne páni. Pre spoločné raňajky a večere oceníte jedálenskú časť a v obývačke si vytvoria svoj „pelech“ deti rôzneho veku. Nájdete tu hračky, detské knižky, ale aj literatúru pre dospelých a spoločenské hry pre každú vekovú skupinu. Do obývačky pohodlne vidíte z kuchyne a baru takže deti aj dospelí majú svoj kľud, pričom sa neprekrikujete, no zároveň máte mládež pod dozorom.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','21c25016-c0d7-429c-bdf1-d801c4d226ce'),
	(2102,2102,1,NULL,'__temp_ezyhzqpwiyzzwgqbqnhnbhasulvnkmauccog',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Bylinková masérňa\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [884, 886, 883, 889, 890], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Masáže\", \"value\": \"{entry:1525@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>V každodennom zhone niet čas na masáž, a ak sa aj nejaký nájde, za masážou je nevyhnutné cestovať. U nás máte možnosť dať si masáž hneď po saune alebo kúpeli v jakuzzi a to je snom asi každého. V našom privátnom wellness si vychutnáte masáž naplno iba Vy a Vaši najbližší. Deti sa zatiaľ zabavia v kolektíve kamarátov alebo so starkými. Vy máte konečne čas a ideálny priestor si vychutnať príjemnú relaxačnú masáž s našim skúseným masérom alebo dostať telo do poriadku s fyzioterapeutom.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','2fd4f0da-0951-40ac-8122-34aba03c2ceb'),
	(2103,2103,1,NULL,'__temp_elcegihenldyvusevljwedzhddvfeeibassh',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Catering\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [601, 602, 599, 606, 604], \"bbab21c5-2ab7-4070-82ca-7673490ba590\": {\"type\": \"entry\", \"title\": \"Stravovanie\", \"value\": \"{entry:1541@1:url}\"}, \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Chutné jedlo patrí ku každej dovolenke či firemnej akcií. Zabezpečíme raňajky, coffee breaky, občerstvenie syrové a masové misy, obedy, večere, grilovačky.</p>\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','9de4e6f9-08e9-4cd0-94bd-1ff5b32791b5'),
	(2104,2104,1,'Prízemie a záhrada','prizemie-a-zahrada',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','84804da7-eafc-4db2-a4e8-87ba8d564075'),
