	(2106,2106,1,'Poschodie','poschodie',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 10:34:54','2026-02-23 10:34:54','1a32d991-68ae-4177-a7fe-394a8006e595'),
	(2107,2107,1,NULL,'__temp_cqicptkdwwjcrbxdvnirkkijsbgstyszunvu',NULL,'{\"2d9f81b3-3665-44b7-935a-c85a3bc9c490\": \"center\", \"6d02377d-9d38-46d1-84c4-07836f4bea30\": \"imageFull\", \"b40963cc-fb78-4a85-9703-9dcd08ed5d91\": false, \"cab8976e-d51f-4252-92cb-87790402a1cf\": [590]}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','202ed394-9bbc-4478-85f1-7eee4d97715b'),
	(2108,2108,1,'Podkrovie','podkrovie',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','4a41cf2c-485e-4a27-ad80-0e53096baf46'),
	(2109,2109,1,NULL,'__temp_eedaosyysqopmydldqjzimydokqqkyjdljgz',NULL,'{\"2d9f81b3-3665-44b7-935a-c85a3bc9c490\": \"center\", \"6d02377d-9d38-46d1-84c4-07836f4bea30\": \"imageFull\", \"b40963cc-fb78-4a85-9703-9dcd08ed5d91\": false, \"cab8976e-d51f-4252-92cb-87790402a1cf\": [587]}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','b36e29de-171f-4950-a425-2530ae3cadfc'),
	(2110,2110,1,NULL,'__temp_iukxsynvrjasaziqxoatrpmxwrevlxwkhzko',NULL,'{\"2d9f81b3-3665-44b7-935a-c85a3bc9c490\": \"center\", \"6d02377d-9d38-46d1-84c4-07836f4bea30\": \"imageFull\", \"b40963cc-fb78-4a85-9703-9dcd08ed5d91\": false, \"cab8976e-d51f-4252-92cb-87790402a1cf\": [586]}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','0c8666d6-11a6-4ca3-a0b1-7222469b2387'),
	(2111,2111,1,'Teambuildingové programy','teambuildingove-programy',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','d1ca70df-ca8f-4c59-a24e-ad4d6f4ef78c'),
	(2112,2112,1,NULL,'__temp_mmgchpuylaozttdidkylptyxhiafyozjpbgb',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Gazdovský deň\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [619, 623, 622, 621, 620], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vyskúšajte si tradičnú prácu gazdov spod Nízkych Tatier. Otestujte si svoju silu, vytrvalosť, ale aj teamového ducha na firemnej akcií v krásnom prostredí spojeným s kvalitným ubytovaním. </p><p>Vyskúšate si práce na poli, pri dreve a statku, ale nakoniec okúsite aj pocit s dobre vykovanej práce.</p>\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','e96685a4-3660-42c1-8dd9-e8a484907b16'),
	(2113,2113,1,NULL,'__temp_qjszzgepdciogqrbxytezgxwgqyxeetefkqz',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Športový deň\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [634, 633, 632, 631, 630], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Najobľúbenejšia možnosť firemnej akcie so športovými aktivitami. Jednotlivé teambuildingové aktivity sú rozmiestnené na trase s prekrásnymi výhľadmi na Nízke Tatry smerujúcej na Pohanské. Tu sa nachádza kaviarnička pohanské kde Vám pripravíme chutnú grilovačku a vychladené pivko. Z Pohanského 30 minútovou prechádzkou pokračujeme na MEGA Lavičku kde zavŕšime váš teambuildingový program spoločnou teamovou fotkou a vyhodnotením.</p><p><strong>Aktivity:</strong></p><p>- maxi lyže<br />- bungeeruning<br />- lukostreľka<br />- trojnohavica<br />- preťahovanie lanom <br />- skákanie vo vreci<br />- crazy okuliare</p>\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','4400bdbd-792c-4dc5-a085-219d86354db7'),
	(2114,2114,1,NULL,'__temp_ljqspywzfegdrhufbmqwkfkyrrdhxctxtsne',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Deň prežitia\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [460, 617, 618, 616, 461], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Zážitková forma teambuildingu, kde sa naučíte ako prežiť v prírode. Vyskúšate si postavenie príbytku, založenie ohňa, ako si zabezpečiť potravu a orientáciu v teréne.</p>\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','1ecdc24d-442e-4c84-a2d7-47e96ac3462c'),
	(2115,2115,1,NULL,'__temp_pqhrpikbkmxvsxkilbpxhpvfefgtwktfjwbr',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Splav Hrona\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [626, 629, 625, 627, 628], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Výborná teambuildingová aktivitá na teplejšie mesiaca od júna do septembra. K dispozícií sú malé aj veľké rafty, a 2 miestne nafukovacie kanoe a kompletné vybavenie na splav. Hron je nenáročná rieka, na ktorej ale nájdete veľa pekných miest a kopec zábavy počas Vašej firemnej akcií. </p><p>Po ceste nájdete maličké zátoky s miestnymi krčmičkami a bufetmi, kde nájdete výbornú vodácku atmosféru. Splav Vám zabezpečíme s dopravou z chaty a spať na 8 miestnej dodávke alebo mikrobuse s kapacitou 21 miest.</p>\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','af9851d8-4fb3-4d3e-935e-9c6ec231ade9'),
	(2116,2116,1,NULL,'__temp_whwshjbbwtgarlwyzowsxzxxoyskckozhciq',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<h2>Sprievodca</h2><p>V regióne Horehronie je mnoho zaujímavých miest a možností výletov, ktoré je možnosť využiť aj pri organizácií firemnej akcií. Niektoré sú známejšie, iné menej. V každom prípade, sprievodca dáva celému výletu úplne iný rozmer a vovedie Vás do miestneho diania, zabezpečí Vám organizáciu, rezervácie, dobré jedlo a vyrieši prípadné požiadavky.</p>\"}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','505988fa-fbdd-4ce5-8802-624c763f629f'),
	(2117,2117,1,NULL,'__temp_bpqctczupfehnsijdxdlzinpghonqgzhlhwx',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"default\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"default\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": true}',1,'2026-02-23 10:34:55','2026-02-23 10:34:55','c9b105bc-4324-4ff6-bcfa-5c57d9746640'),
