	(2174,2174,1,'Cenník ubytovania','cennik-ubytovania',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"left\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 11:31:08','2026-02-23 11:31:08','606b595c-adf2-4e81-ba44-3c77cd51be44'),
