	(2258,2258,1,'Apartmány a izby','apartmany-a-izby','ubytovanie/apartmany-a-izby','{\"d401a70e-ad52-421a-9c71-f5991a71306a\": 10}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','6267cec1-da40-4420-950a-900df82c870d'),
	(2259,2259,1,NULL,'__temp_pchdnustpzwvurvmxspkglyzjlfxobdmoqqs',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Rodinný apartmán\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1154, 1155, 1149, 1143, 1140], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Dve samostatné spálne, obývačka s kuchyňou, veľká kúpeľňa s vaňou. </strong></p><p>Ideálny výber pre <strong>veľkú 6-člennú rodinu, rodinu so staršími deťmi, rodinu so starými rodičmi alebo dve spriatelené rodinky</strong>. Apartmán má vlastnú vstupnú chodbu, čo umožňuje pohyb po apartmáne bez toho, aby ste rušili neskorým pochodom do kúpeľne spiace deti. Veľká „3-izbová kúpeľňa“ so sprchovým kútom a s vaňou poteší deti a rodičom dopraje priestor na záverečný relax pred spánkom. Zlatá romantická spálňa je pripravená pre páry, ktoré radi načúvajú praskotu dreva v piecke.</p>\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','5541375e-0167-4167-8162-1556292b5bb9'),
	(2260,2260,1,NULL,'__temp_xzlspheymlrxlmxflswelwmlzullleccvnjs',NULL,'{\"0b9f4dca-5d17-4549-b0d6-540da11a1c61\": [521], \"82e8c982-58a5-428d-855a-c34647291dad\": \"WiFi\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','8cd9ad96-8225-4fd9-9ae7-152d63eea25b'),
	(2261,2261,1,NULL,'__temp_nxixggroyhzoxwwbxhizvaphiwgcicasvkcx',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"2-lôžková izba č.4\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1111, 1116, 1115, 1113, 1112], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Manželská posteľ + detská postieľka </strong></p><p>Izba sa nachádza na prízemí, vhodná pre rodinu s bábätkom alebo pár.</p>\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','e1a42a87-14ef-4139-bd93-7e1a9d1a35eb'),
	(2262,2262,1,NULL,'__temp_knpkioaqatsglgtuytdhzylzkmbtrlokxpwe',NULL,'{\"0b9f4dca-5d17-4549-b0d6-540da11a1c61\": [521], \"82e8c982-58a5-428d-855a-c34647291dad\": \"WiFi\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','210de21d-cd20-48fc-a1a3-f13ba48585d2'),
	(2263,2263,1,NULL,'__temp_eaojedfzhsucbcnfuwlgefonahyrdevkjlle',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"3-lôžková izba č.5\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1125, 1128, 1134, 1131, 1130], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Manželská posteľ + 1-lôžko</strong></p><p>Útulná izba vhodná pre rodinu s malými deťmi, ktorá rada spí pokope. Postele je možné jednoducho presúvať.</p>\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','7a7477cc-72f4-4ae9-b68d-c1cc76e70f6b'),
	(2264,2264,1,NULL,'__temp_csweqeaigodtfxdnacsjfiwiinjzbhzdduaj',NULL,'{\"0b9f4dca-5d17-4549-b0d6-540da11a1c61\": [521], \"82e8c982-58a5-428d-855a-c34647291dad\": \"WiFi\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','e3e9818b-5aa4-4eb7-afa6-8593f4c10ae1'),
	(2265,2265,1,NULL,'__temp_blutnwzybeihhtzbxkvkmodrxyhfocvyrdbp',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Štúdio – izba č.6\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [1117, 1118, 1119, 1121, 1120], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Manželská posteľ + rozťahovacia pohovka</strong></p><p><strong>Priestranná izba na prízemí s výhľadom do záhrady</strong>, uspôsobená spolu s kúpeľnou pre imobilných hostí. Z izby je všade blízko - do spoločenskej miestnosti, do wellness, altánku či záhrady s detským ihriskom.</p><p>Nájdeme tu <strong>plne vybavenú kuchynku</strong> - 2 platnička, drez, malá chladnička, kanvica, vybavenie pre základné stolovanie a poháre pre 4 osoby, hrnce, panvica, nože, vývrtka na víno.</p>\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','6deb751f-e3d0-44b7-80e6-1ecf703d5085'),
	(2266,2266,1,NULL,'__temp_clbsjjsstcckqutvrzhmpzuuvbqsfntxcrkk',NULL,'{\"0b9f4dca-5d17-4549-b0d6-540da11a1c61\": [521], \"82e8c982-58a5-428d-855a-c34647291dad\": \"WiFi\"}',1,'2026-02-23 11:37:20','2026-02-23 11:37:20','b49a68fc-8c2b-49a3-ac3d-48c691e3e29a'),
	(2289,2289,1,NULL,'__temp_sdahjoxelhyjgvsmynmarbswdmughmmhhsgb',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Predstavujete si ubytovanie, ktoré má niečo viac ako len pohodlnú posteľ, kúpeľňu či spoločenskú miestnosť? Hľadáte a stále nenachádzate? Práve ste našli. Horská Vílenka v Mýte pod Ďumbierom v údolí Nízkych Tatier je plná zážitkov, ba čo viac \\\"je viac než len ubytovanie\\\". Tešíme sa na spoločné zážitky...:)</p>\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','68de30cd-25d4-44d1-9447-3717e9e884c7'),
	(2290,2290,1,NULL,'__temp_ursnqfpynzcwkvpodkwprbuewbsqgbafafhf',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','6f0c256c-b0e5-42cf-89dd-a4e59c25d03f'),
	(2291,2291,1,'3D Prehliadka','3d-prehliadka',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','736ee185-41ef-4ce9-a395-64aa5d1dd4a3'),
	(2292,2292,1,NULL,'__temp_cpvcgildgwssucgkmqtcsuazxqapqxnreczl',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/sk/tour/horska-vilenka frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','ae54f6ef-6a2b-4a40-bb85-9ba87ebc9194'),
	(2293,2293,1,NULL,'__temp_tmnbkqgpqohemesyttchmlictqeyyrifmpbj',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"smaller\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"smaller\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": false}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','baf0fb86-043f-4402-b67b-1bbb9779e2de'),
	(2294,2294,1,NULL,'__temp_sxygpeijofcjgsvoocdatdcmihzzsagjwgnq',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Wellness v súkromí\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [434, 869, 870, 872, 868], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vykročte v papučiach do záhrady a dovoľte si objaviť náš malý raj. Fínska sauna s troma lavicami pre 9 osôb, ochladzovacia kaďa, solárna sprcha, odpočinková miestnosť je to, čo potrebujete k dokonalému znovuzrodeniu.</p><p>Na požiadanie saunu pripravíme v dohodnutý čas, a tak po príchode z výletu môže Vaše telo plynulo zrelaxovať. Prírodné bylinné esencie sú vždy k dispozícií. Pre náročnejších či zvedavých wellnesákov ponúkame <strong>saunový ceremoniál</strong>. Pravdaže nechýba záhradná kúpeľňa „Bob a Bobek“ s WC a sprchou, kde sa s radosťou určite osprchujú aj Vaše ratolesti.</p>\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','33584a6a-ce0d-4daf-8f2e-f1951639e6f8'),
	(2295,2295,1,NULL,'__temp_ezdzvfzngycjdpbklacjqjagseoqwgbwcnkc',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Vonkajší bazén\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [420, 423, 419, 418, 415], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vonkajší bazén je to, čo si v našej chate zamilujete. V prípade rodín s deťmi, nebudete musieť počúvať \\\"kedy už pôjdeme na kúpalisko\\\". Stačí vyjsť na dvor, deti sa vyčľapkajú a rodičia si oddýchnu bez ďalších investícií a šoférovania. <br /><br />Pre dospelých nie je lepší pocit, ako sa po túre vyvaliť do bazéna a zregenerovať boľavé nohy, poprípade si vychutnať romantické večerné kúpanie pod hviezdami.</p>\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','76a01143-1762-4ca0-8277-85fde802c85c'),
	(2296,2296,1,NULL,'__temp_lqyvavdtpuiktqttdenthxrlnwbsiuacysyk',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Masáže\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [884, 883, 891, 450, 892], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>V každodennom zhone niet čas na masáž, a ak sa aj nejaký nájde, za masážou je nevyhnutné cestovať. U nás máte možnosť dať si masáž hneď po saune alebo kúpeli v jacuzzi a to je snom asi každého. V našom privátnom wellness si vychutnáte masáž naplno iba Vy a Vaši najbližší. Deti sa zatiaľ zabavia v kolektíve kamarátov alebo so starkými. Vy máte konečne čas a ideálny priestor si vychutnať príjemnú relaxačnú masáž s našim skúseným masérom alebo dostať telo do poriadku s fyzioterapeutom.</p>\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','4145d020-6138-4ea1-b747-14b203e87851'),
	(2297,2297,1,NULL,'__temp_ibsztboyakphzsjbtuagranvxmicbgnntidr',NULL,'{\"0b9f4dca-5d17-4549-b0d6-540da11a1c61\": [509], \"82e8c982-58a5-428d-855a-c34647291dad\": \"Fínska sauna\"}',1,'2026-02-23 13:16:57','2026-02-23 13:16:57','be30fbc0-8c41-4b46-9e2d-278aafe7b76e'),
