	(2495,2495,1,NULL,'__temp_ldhfalxpblnlmrlgapprflwfpqfscgupkkhn',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Raňajky, ale aj kompletné stravovanie Vám radi zabezpečíme priamo na chatu formou cateringu. Na grilovačku Vám vieme prepožičať nášho gril majstra, ktorý ponúka kompletnú prípravu i servírovanie hotových špecialít. Reštauráciu s domácou kuchyňou nájdete približne 100 m od chaty a výbornú letnú kaviarničku vzdialenú do päť minút pešou chôdzou.</p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','2f1b496c-ab27-4896-9d11-6b34228e6d9c'),
	(2496,2496,1,NULL,'__temp_jcmmechxlwwpncjqerplmeaivhtljwqcqgln',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Raňajky\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [425, 609, 607, 606, 611], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Zobuďte sa ráno v <strong>Nízkych Tatrách</strong>. <strong>Kvalitné ubytovanie s poctivými raňajkami </strong>je základ každej dovolenky či firemného pobytu. Vychutnajte si ich v <strong>lete na záhrade</strong> alebo v spoločenskej miestnosti. Raňajky pripravujeme z <strong>kvalitných surovín</strong> tak, aby si každý našiel to svoje. <strong>Praženičky na masle</strong>, volské oká či párky Vám pripravíme na požiadanie <strong>vždy čerstvé a teplé</strong>. </p><p>V prípade raňajok počas dlhších pobytov pre Vás pripravíme po večernej dohode aj rôzne <strong>pomazánky, zapekané tousty, krupicovú kašu</strong>, vločky či <strong>domáci puding</strong> pre malých aj veľkých.</p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','c0445d4b-1e7a-4292-bcce-ce4bb4609d5c'),
	(2497,2497,1,NULL,'__temp_dfyuubqytgyrfleratmmoqcwyslfaygdixei',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Grilovanie a gulášik\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [471, 472, 469, 473, 474], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Vulcano gril</strong> vyzerá ako obyčajné ohnisko, no po grilovačke na ňom je každý potešený jeho <strong>nespočetnými možnosťami a výhodami</strong>. Pripravíte si tu kompletnú grilovačku pre <strong>20 osôb</strong>, v <strong>nerezovom voku uvaríte výborné soté,</strong> menší gulášik alebo omáčky. </p><p>K dispozícií je aj <strong>30 l nerezová kotlina na guláš</strong> a pripravená je aj veľká naberačka s varechou, tú veríme, že použijete len na miešanie toho gulášu.</p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','179c5b56-c5e4-4f6b-a018-944c9021af90'),
	(2498,2498,1,NULL,'__temp_ijcbkglmsivbzojbtoyblxubltlsdrvvbeef',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Catering\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [603, 599, 605, 604, 602], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Chutné jedlo patrí ku každej dovolenke či firemnej akcií. Zabezpečíme raňajky, coffee breaky, občerstvenie syrové a mäsové misy, obedy, večere, grilovačky.</p><p>Zabezpečiť Vám vieme aj profesionálneho gril majstra, ktorý pripraví všetko pred Vašimi očami. Vychutnať si môžete:</p><p>steaky</p><p>špízy</p><p>kotlety</p><p>hamburgery</p><p>grilovanú zeleninku</p><p>grilovaný syr</p><p>pečené zemiačky v pahrebe</p><p>čerstvý zeleninový šalát</p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','6149d869-bb94-4a0f-b7b2-37adc8920689'),
	(2499,2499,1,NULL,'__temp_uhqpvmsonjknhtxersxhqjwowjqxeqkjlwxk',NULL,'{\"12fb1e10-9f6f-4acb-aba8-789f107b07b0\": \"default\", \"1b6c7209-a337-4255-b3dc-a262768a2d60\": \"default\", \"8a3e7279-eb49-4331-a669-34d48b31c79c\": true}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','1cbfaf45-0ea8-4135-a2ac-a76414523f87'),
	(2500,2500,1,'V rámci cateringu ponúkame','v-ramci-cateringu-ponukame',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"left\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','2f14aa06-8824-4717-b305-264f065debde'),
	(2501,2501,1,NULL,'__temp_kultudnuyjxehuprxnthxhiaymvkgwstudap',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p><strong>Ponuka cateringu sa priebežne mení, aby sme išli s najnovšími trendmi. Radi Vám tú aktuálnu zašleme na požiadanie.</strong></p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','aee659d5-849b-471b-bcc9-9bb38948e66b'),
