	(2509,2509,1,NULL,'__temp_dfyuubqytgyrfleratmmoqcwyslfaygdixei',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Grilovanie a gulášik\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [471, 472, 469, 473, 474], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Vulcano gril</strong> vyzerá ako obyčajné ohnisko, no po grilovačke na ňom je každý potešený jeho <strong>nespočetnými možnosťami a výhodami</strong>. Pripravíte si tu kompletnú grilovačku pre <strong>20 osôb</strong>, v <strong>nerezovom voku uvaríte výborné soté,</strong> menší gulášik alebo omáčky. </p><p>K dispozícií je aj <strong>30 l nerezová kotlina na guláš</strong> a pripravená je aj veľká naberačka s varechou, tú veríme, že použijete len na miešanie toho gulášu.</p>\"}',1,'2026-02-23 14:43:12','2026-02-23 14:43:12','5ed9031b-6e85-4ac4-a39e-46a398843c7d'),
