	(2534,2534,1,NULL,'__temp_sskekxncnsnoncsjziuyhitzedxyzyalpjob',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Po privítaní Vás exkurziou po chate vovedieme do časopriestoru oddychu a pokoja. Očarí Vás priestranný wellness, záhrada, altánok s výhľadom na detské ihrisko, priestranná spoločenská miestnosť či samostatná obývačka s detským kútikom.</p>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','fb4fa063-0184-49fe-8df5-c01373fd1952'),
	(2535,2535,1,'3D Prehliadka','3d-prehliadka',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','6d3c4069-7a3e-43ea-8f69-3ad427ff7ea7'),
	(2536,2536,1,NULL,'__temp_qayougcokrljbewpaiwxxualbsmxmxohqnzq',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/tour/horska-vilenka?play=1&sr=-1.91,-1.11&ss=138 frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','02a92a58-ecee-4130-9146-22b90695de60'),
	(2537,2537,1,NULL,'__temp_uqmqwcxmgadgpwrkfbkqqyljtqizpdptzzio',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Máte radi Letné grilovačky? - Altánok a záhrada\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [445, 471, 473, 470, 442], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Praskajúci oheň, víno s priateľmi, nekonečné debaty alebo príjemné ticho pod hviezdami. Zabavte sa pri žolíkovi či pomaly už historických dostihoch a užite si príjemné chvíle s najbližšími. Odvážnych, ale aj unavených v altánku poteší váľanda.</p><p>Dominantný VULCANO gril čaká na Vašu obľúbenú zeleninu a mäsko či pozbierané hríbiky. Gulášik pre celú rodinu pripravíte zase v nerezovej kotline.</p>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','8b3b65ba-4cf4-4e60-a5d6-d5d321825c87'),
	(2538,2538,1,NULL,'__temp_msfgcxliyrvzrflcnvnmzkanfhlqmhuejbhl',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Aktivity pre deti – detské ihrisko\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [475, 478, 467, 466, 427], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Deti sa na záhrade bezpečne prehrajú, a najlepšie je, že ich máte v dohľade z oddychovej zóny altánku či wellness. Vyšantia sa na hojdačkách, šmýkačke, malkáči sa radi zarobotia v pieskovisku, a už skoro veľkáči sa môžu dosýtosti vyskákať na trampolíne.</p><p>V prípade záujmu zabezpečíme opatrovateľskú službu so zodpovednou osobou. Deti sa zabavia, zahrajú hry, zaspievajú, nakreslia obrázky, zatiaľ čo Vy máte čas na wellness, masáže, romantický výlet či večeru.</p>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','8b3a17fd-8e34-470c-aad5-f6afa66c62ef'),
	(2539,2539,1,NULL,'__temp_arnhtvgvsvrhncyqrmbxkjalwmlkntknbtbh',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Dlhoročným saunovaním vyladené wellness\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [867, 436, 434, 435, 872], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vykročte v papučiach do záhrady a dovoľte si objaviť náš malý raj. Vonkajší bazén, fínska sauna s troma lavicami pre 9 osôb, ochladzovacia kaďa, solárna sprcha, odpočinková miestnosť je to, čo potrebujete k dokonalému znovuzrodeniu. Na požiadanie saunu pripravíme v dohodnutý čas, a tak po príchode z výletu môže Vaše telo plynulo zrelaxovať. Prírodné bylinné esencie sú vždy k dispozícií. Pre náročnejších či zvedavých wellnesákov ponúkame <strong>saunový ceremoniál</strong>. Pravdaže nechýba záhradná kúpeľňa „Bob a Bobek“ s WC a sprchou, kde sa s radosťou určite osprchujú aj Vaše ratolesti.</p>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','6444c83f-27ab-46b4-ae4f-ae70ebe46197'),
	(2540,2540,1,NULL,'__temp_kcwlxrvjkcjuupyihhqasexzfngkkfxpiudn',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Vonkajší bazén\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [420, 423, 419, 418, 415], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Vonkajší bazén je to, čo si v našej chate zamilujete. V prípade rodín s deťmi, nebudete musieť počúvať \\\"kedy už pôjdeme na kúpalisko\\\". Stačí vyjsť na dvor, deti sa vyčľapkajú a rodičia si oddýchnu bez ďalších investícií a šoférovania. <br /><br />Pre dospelých nie je lepší pocit, ako sa po túre vyvaliť do bazéna a zregenerovať boľavé nohy, poprípade si vychutnať romantické večerné kúpanie pod hviezdami.</p>\"}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','7ab1c5e2-079b-4f22-99b9-52249a4f8c06'),
	(2541,2541,1,NULL,'__temp_kgbqwoxcfmprmcqywusxsptueaahkpsimzmu',NULL,'{\"dd915635-0f22-4dbc-bc32-3529f7e19daa\": [445]}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','f65a3063-799f-4821-9273-025b431ba4f5'),
