	(2545,2545,1,'Záhrada','zahrada','zahrada','{\"d401a70e-ad52-421a-9c71-f5991a71306a\": 5}',1,'2026-02-23 15:00:57','2026-02-23 15:00:57','bb40fbcc-f0d7-4b96-a88c-7da806889749'),
	(2546,2546,1,NULL,'__temp_sskekxncnsnoncsjziuyhitzedxyzyalpjob',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>Po privítaní Vás exkurziou po chate vovedieme do časopriestoru oddychu a pokoja. Očarí Vás priestranný wellness, záhrada, altánok s výhľadom na detské ihrisko, priestranná spoločenská miestnosť či samostatná obývačka s detským kútikom.</p>\"}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','c0392ba0-c505-4416-8b45-3c112a5f69a3'),
	(2547,2547,1,'3D Prehliadka','3d-prehliadka',NULL,'{\"315b7a3d-e9d0-467b-81db-dba49df32567\": \"center\", \"343443cd-502c-4d7c-b962-db38d3f18c1b\": \"h2\"}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','ecec833b-1d2e-448a-b74e-3e18fbbead30'),
	(2548,2548,1,NULL,'__temp_qayougcokrljbewpaiwxxualbsmxmxohqnzq',NULL,'{\"deb35a50-a7c0-4d90-ab01-2c07189845aa\": \"<iframe width=\\\"100%\\\" height=\\\"500\\\" src=https://my.roowax.sk/tour/horska-vilenka?play=1&sr=-1.91,-1.11&ss=138 frameborder=\\\"0\\\" allowfullscreen></iframe>\"}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','d0c4c55f-3b7f-4037-afce-5d7421c6a2b5'),
	(2549,2549,1,NULL,'__temp_uqmqwcxmgadgpwrkfbkqqyljtqizpdptzzio',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Máte radi Letné grilovačky? - Altánok a záhrada\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [445, 471, 473, 470, 442], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Praskajúci oheň, víno s priateľmi, nekonečné debaty alebo príjemné ticho pod hviezdami. Zabavte sa pri žolíkovi či pomaly už historických dostihoch a užite si príjemné chvíle s najbližšími. Odvážnych, ale aj unavených v altánku poteší váľanda.</p><p>Dominantný VULCANO gril čaká na Vašu obľúbenú zeleninu a mäsko či pozbierané hríbiky. Gulášik pre celú rodinu pripravíte zase v nerezovej kotline.</p>\"}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','7de83407-c22b-4243-a23c-ed56a2b05aef'),
	(2550,2550,1,NULL,'__temp_msfgcxliyrvzrflcnvnmzkanfhlqmhuejbhl',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Aktivity pre deti – detské ihrisko\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [475, 478, 467, 466, 427], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p>Deti sa na záhrade bezpečne prehrajú, a najlepšie je, že ich máte v dohľade z oddychovej zóny altánku či wellness. Vyšantia sa na hojdačkách, šmýkačke, malkáči sa radi zarobotia v pieskovisku, a už skoro veľkáči sa môžu dosýtosti vyskákať na trampolíne.</p><p>V prípade záujmu zabezpečíme opatrovateľskú službu so zodpovednou osobou. Deti sa zabavia, zahrajú hry, zaspievajú, nakreslia obrázky, zatiaľ čo Vy máte čas na wellness, masáže, romantický výlet či večeru.</p>\"}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','2aea67da-4866-474c-902b-a78069448364'),
