	(2556,2556,1,NULL,'__temp_ftoawyunpphgvifwcsbsrgjsqlryzuzlwigm',NULL,'{\"dd915635-0f22-4dbc-bc32-3529f7e19daa\": [429]}',1,'2026-02-23 15:00:58','2026-02-23 15:00:58','5a273d8e-ec64-46b3-a5e9-62cc131d085f'),
	(2563,2563,1,NULL,'__temp_hkugivlcyojudyznycypcsumysfgkmenvxqi',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Hracia miestnosť s kinom\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [532, 536, 533, 540, 539], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Ideálny a kreatívny priestor pre deti, ktoré sa tu vyšantia. Je výbornou alternatívou aj v prípade horšieho počasia. </strong></p><p>Okrem stolného futbalu a hracieho stolu je k dispozícií aj kvalitný projektor s 4K obrazom a 300´´ plátnom, kde bude sledovanie filmov či rozprávok nezabudnuteľný zážitok bez boľavých očí vyťahaných od displeja. Projektor má výbornú svietivosť, takže sledovanie nie je problém aj počas dňa. Miestnosť má inteligentné osvetlenie a tak je navodenie príjemnej atmosféry zaručené.</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','8ef4bfb0-7521-4967-a46d-abe034d43e78'),
	(2564,2564,1,NULL,'__temp_ynogbczbbirdxhqrqpjtmnvchpjghtrqnllv',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Semináre, Workshopy, joga, meditácie\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [529, 451, 527, 526, 530], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Aj na dopyt od našich hostí a záujemcov, sme vytvorili nový útulný a inšpiratívny priestor. Veríme, že Vás osloví a čoskoro si ho vyskúšate.</strong></p><p>Radi privítame rôzne organizované pobyty, pre ktoré je tiež k dispozícií:</p><p>- nápojová kuchynka<br />- 12 x karimatiek<br />- 6 x schiatsu futóny<br />- nastaviteľná intenzita svetla<br />- možnosť na 99% zatemniť miestnosť<br />- kúpeľňa (WC, umývadlo, sprcha)<br />- ozvučenie</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','7117df4e-66e9-4126-b964-13a457983434'),
	(2565,2565,1,NULL,'__temp_zvvtydwubiwfhbtdfkazdkvcpmluvezpzuik',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Školiaca a zasadacia miestnosť\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [542, 550, 556, 548, 549], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Samostatný priestor pre Vaše firemné porady, školenia či workshopy. V chate tak máte priestor pre každú činnosť Vášho tímu. </strong></p><p><strong>Kapacita</strong>: zasadačka 13 miest, školenia 15 miest na sedenie</p><p><strong>Technické vybavenie</strong>:<br />- premietacie plátno 300\\\" ( 225 x 125 cm )<br />- kvalitný projektor<br />- flip chart - písacie dosky</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','2c3899e4-555c-484d-b123-1a02c7ab46f1'),
	(2566,2566,1,NULL,'__temp_esnmvahbqrlfqfhxpruwpxzphcugfqeqljhe',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Izba na spanie\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [559, 557, 558, 560, 562], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Miestnosť Vám vieme pripraviť ako izbu s možnosťou spania na šiestich futónoch (japonský matrac) s kompletným postieľaním, osuškou a uterákom.</strong></p><p>K dispozícií je malá nápojová kuchynka s chladničkou, kúpeľňa s toaletou, sprchou a umývadlom. Schody do miestnosti sú od hlavnej chodby oddelené dverami, pri schodisku sa nachádza malé posedenie s knižnicou.</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','e6f4adba-35cb-4882-9054-6249ef7fda37'),
	(2567,2567,1,'Multifunkčná miestnosť','multifunkcna-miestnost','multifunkcna-miestnost',NULL,1,'2026-02-23 15:12:35','2026-02-23 15:12:35','0641b41c-ec74-4b1a-8300-8c6e007bf1cd'),
	(2568,2568,1,NULL,'__temp_jjylygenskjhpcydvkwhmcjywytmhvcayvzm',NULL,'{\"f169d119-ae72-4ffa-8237-b5335510826d\": \"<p>K dispozícií je podkrovná miestnosť o rozlohe 60 m² s vlastnou kúpeľnou a nápojovou kuchynkou. Miestnosť má príjemnú atmosféru s vysokým (ihlanovým) stropom. Je celý otvorený no zároveň si v ňom každý vie nájsť svoj kútik. V celej miestnosti je komfortný mäkký koberec. Do miestnosti sa vstupuje cez samostatné uzavreté schodisko s malým posedením, do ktorého je vstup z chodby na 1. poschodí. Na oknách sú inštalované zatemňovacie rolety, takže v prípade potreby absolútnej/čiastočnej tmy aj počas dňa Vám vieme vyhovieť. Miestnosť má inteligentné osvetlenie s jednotlivými scénami pre rôzne využitie miestnosti.</p><h3>Miestnosť pre Vás vieme pripraviť v nasledovných variantoch:</h3><ol><li><strong>Hracia miestnosť s kinom</strong> - stolný futbal, hrací stôl, futóny s vankúšmi, kvalitný 4K projektor s 300´´ plátnom.</li><li><strong>Semináre, Workshopy, joga, meditácie</strong> – čistý priestor, k dispozícií je 12 ks karimatiek.</li><li><strong>Školiaca a zasadacia miestnosť </strong>– 15 ks stoličiek, 3 ks stôl 120 x 70 cm, projektor, plátno, flip chart, písacie dosky.</li><li><strong>Izba na spanie </strong>– 6 ks futón s postieľaním.</li></ol>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','789be739-9269-4b6a-9bff-aef9962df217'),
	(2569,2569,1,NULL,'__temp_hkugivlcyojudyznycypcsumysfgkmenvxqi',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Hracia miestnosť s kinom\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [532, 536, 533, 540, 539], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Ideálny a kreatívny priestor pre deti, ktoré sa tu vyšantia. Je výbornou alternatívou aj v prípade horšieho počasia. </strong></p><p>Okrem stolného futbalu a hracieho stolu je k dispozícií aj kvalitný projektor s 4K obrazom a 300´´ plátnom, kde bude sledovanie filmov či rozprávok nezabudnuteľný zážitok bez boľavých očí vyťahaných od displeja. Projektor má výbornú svietivosť, takže sledovanie nie je problém aj počas dňa. Miestnosť má inteligentné osvetlenie a tak je navodenie príjemnej atmosféry zaručené.</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','ef379e37-ab8f-467c-9567-dbb45b76a39e'),
	(2570,2570,1,NULL,'__temp_ynogbczbbirdxhqrqpjtmnvchpjghtrqnllv',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Semináre, Workshopy, joga, meditácie\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [529, 451, 527, 526, 530], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Aj na dopyt od našich hostí a záujemcov, sme vytvorili nový útulný a inšpiratívny priestor. Veríme, že Vás osloví a čoskoro si ho vyskúšate.</strong></p><p>Radi privítame rôzne organizované pobyty, pre ktoré je tiež k dispozícií:</p><p>- nápojová kuchynka<br />- 12 x karimatiek<br />- 6 x schiatsu futóny<br />- nastaviteľná intenzita svetla<br />- možnosť na 99% zatemniť miestnosť<br />- kúpeľňa (WC, umývadlo, sprcha)<br />- ozvučenie</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','2c222cd7-e23f-4eb8-acaa-5f897fdc73ed'),
	(2571,2571,1,NULL,'__temp_zvvtydwubiwfhbtdfkazdkvcpmluvezpzuik',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Školiaca a zasadacia miestnosť\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"right\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [542, 550, 556, 548, 549], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Samostatný priestor pre Vaše firemné porady, školenia či workshopy. V chate tak máte priestor pre každú činnosť Vášho tímu. </strong></p><p><strong>Kapacita</strong>: zasadačka 13 miest, školenia 15 miest na sedenie</p><p><strong>Technické vybavenie</strong>:<br />- premietacie plátno 300\\\" ( 225 x 125 cm )<br />- kvalitný projektor<br />- flip chart - písacie dosky</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','c0315db8-2804-4ae4-a538-7eea5df79adf'),
	(2572,2572,1,NULL,'__temp_esnmvahbqrlfqfhxpruwpxzphcugfqeqljhe',NULL,'{\"7a26fa3c-ec4b-4ef7-9870-00e57761babd\": \"Izba na spanie\", \"91bd6c44-9940-446d-b560-c987a0a8b6d5\": \"left\", \"b4ff9ca2-9009-43df-8638-ab3928643dbb\": [559, 557, 558, 560, 562], \"d53c4bc8-0107-4e67-8495-cc0c5d3210fb\": \"<p><strong>Miestnosť Vám vieme pripraviť ako izbu s možnosťou spania na šiestich futónoch (japonský matrac) s kompletným postieľaním, osuškou a uterákom.</strong></p><p>K dispozícií je malá nápojová kuchynka s chladničkou, kúpeľňa s toaletou, sprchou a umývadlom. Schody do miestnosti sú od hlavnej chodby oddelené dverami, pri schodisku sa nachádza malé posedenie s knižnicou.</p>\"}',1,'2026-02-23 15:12:35','2026-02-23 15:12:35','7b8cfb9e-534b-4ff0-a675-ee7f55d5e840');
