	(5,'Facebook Handle','facebookHandle','global',NULL,'Your Facebook company/fan page handle (the part after https://www.facebook.com/)',1,'none',NULL,'craft\\fields\\PlainText','{\"byteLimit\":null,\"charLimit\":null,\"code\":false,\"initialRows\":4,\"multiline\":false,\"placeholder\":null,\"uiMode\":\"normal\"}','2024-06-03 17:02:08','2024-06-03 17:02:08',NULL,'5410b80a-d2c8-4d87-bce0-7e047145966d'),
	(6,'Google Analytics Tracking ID','analyticsId','global',NULL,'If you enter your Google Analytics Tracking ID here, the Google Analytics script tags will be included in your <head> (the script is not included if devMode is on or during Live Preview). Only enter the ID, e.g.: UA-XXXXXX-XX, not the entire script code. [Here\'s how to get it](https://support.google.com/analytics/answer/1032385?hl=en).',0,'none',NULL,'craft\\fields\\PlainText','{\"byteLimit\":null,\"charLimit\":15,\"code\":true,\"initialRows\":4,\"multiline\":false,\"placeholder\":null,\"uiMode\":\"normal\"}','2024-06-03 17:04:37','2024-06-03 17:04:37',NULL,'7ab49e1d-8c4e-4b01-b832-02d8c69746ef'),
	(7,'Hide Sidebar','hideSidebar','global',NULL,NULL,0,'none',NULL,'craft\\fields\\Lightswitch','{\"default\":false,\"offLabel\":null,\"onLabel\":null}','2024-06-03 17:05:16','2024-06-03 17:05:16',NULL,'f7e7cbc6-dbf6-4e59-9430-a7728d67524d'),
	(8,'Nadpis stránky','pageHeading','global',NULL,'Použite, ak má byť nadpis stránky iný, ako názov stránky.',1,'none',NULL,'craft\\fields\\PlainText','{\"byteLimit\":null,\"charLimit\":null,\"code\":false,\"initialRows\":4,\"multiline\":false,\"placeholder\":\"Leave empty if same as Page Title\",\"uiMode\":\"normal\"}','2024-06-03 17:06:01','2026-02-17 09:30:26',NULL,'9ba82f61-ac54-4bfe-827b-e506e0d79ff6'),
