	(10,'Section Template Folder','sectionTemplateFolder','global',NULL,NULL,0,'none',NULL,'craft\\fields\\PlainText','{\"byteLimit\":null,\"charLimit\":null,\"code\":false,\"initialRows\":4,\"multiline\":false,\"placeholder\":null,\"uiMode\":\"normal\"}','2024-06-03 17:08:44','2024-06-03 17:08:44',NULL,'f8b138be-9608-4b14-91eb-d59aa08a08c4'),
